import subprocess

# Generate requirements.txt with hashes
subprocess.run(["pip", "freeze", "--local", "--hash", ">", "requirements.txt"])

# Generate Poetry lock file
subprocess.run(["poetry", "lock", "--no-dev"])

# Update dependency specifications
def update_dependencies():
    # Run pip freeze to get current dependency versions
    pip_freeze_output = subprocess.check_output(["pip", "freeze", "--local"]).decode("utf-8")

    # Write updated requirements.txt with new versions
    with open("requirements.txt", "w") as f:
        for line in pip_freeze_output.splitlines():
            package_name, version = line.split("==")
            f.write(f"{package_name}=={version}\n")

    # Run poetry update to update Poetry lock file
    subprocess.run(["poetry", "update"])

# Call the function to update dependencies
update_dependencies()